// ── InnerShadowDecoration ────────────────────────────────────────────────────
//
// A drop-in Decoration for true CSS-style inset shadows.
//
// Flutter's BoxShadow(blurStyle: BlurStyle.inner) does not work correctly with
// the Impeller renderer (Flutter ≥ 3.10). This implementation uses the
// clip-and-offset CustomPainter technique which works on both Skia and Impeller.
//
// IMPORTANT — blur mapping:
//   CSS  box-shadow blur uses the value as the Gaussian sigma directly.
//   Flutter BoxShadow.blurSigma applies a lossy conversion (r×0.577+0.5) that
//   produces a much softer result than CSS.  We intentionally pass blurRadius
//   directly to MaskFilter so Flutter matches the CSS output.
//
// Usage — identical mental model to CSS inset:
//
//   // CSS
//   style={{ boxShadow: BTechShadow.button.pressed }}   // "inset 0 4px 4px …"
//
//   // Flutter
//   Container(
//     decoration: InnerShadowDecoration(
//       color: context.btechColor.background.primary,
//       borderRadius: BorderRadius.circular(BTechRadius.sm),
//       boxShadow: BTechShadow.button.pressed,
//     ),
//   )

class InnerShadowDecoration extends Decoration {
  const InnerShadowDecoration({
    this.color,
    this.borderRadius,
    this.border,
    this.boxShadow = const [],
  });

  /// Background fill.
  final Color? color;

  /// Corner radius — pass BorderRadius.circular(BTechRadius.sm) etc.
  final BorderRadiusGeometry? borderRadius;

  /// Optional border drawn beneath the shadow layer.
  final BoxBorder? border;

  /// Inner shadow layers.  Pass BTechShadow.button.pressed directly.
  /// The blurStyle field on each BoxShadow is ignored — always rendered inset.
  final List<BoxShadow> boxShadow;

  // ── Lerp ───────────────────────────────────────────────────────────────────

  @override
  InnerShadowDecoration lerpFrom(Decoration? a, double t) {
    if (a is InnerShadowDecoration) return InnerShadowDecoration.lerp(a, this, t)!;
