// ── _InnerShadowBoxPainter ───────────────────────────────────────────────────

class _InnerShadowBoxPainter extends BoxPainter {
  _InnerShadowBoxPainter(this._dec, VoidCallback? onChanged) : super(onChanged);

  final InnerShadowDecoration _dec;

  @override
  void paint(Canvas canvas, Offset offset, ImageConfiguration config) {
    final size   = config.size ?? Size.zero;
    final rect   = offset & size;
    final radius = (_dec.borderRadius?.resolve(config.textDirection)
        ?? BorderRadius.zero) as BorderRadius;
    final rrect  = radius.toRRect(rect);

    // 1. Background
    if (_dec.color != null) {
      canvas.drawRRect(rrect, Paint()..color = _dec.color!);
    }

    // 2. Border
    _dec.border?.paint(canvas, rect, borderRadius: radius);

    // 3. Inner shadow layers
    for (final shadow in _dec.boxShadow) {
      _paintInner(canvas, rrect, shadow);
    }
  }

  void _paintInner(Canvas canvas, RRect rrect, BoxShadow shadow) {
    final rect = rrect.outerRect;

    // "Wall" path: a rect large enough to always surround the widget in every
    // direction, with the widget's rounded shape subtracted from it.
    // When shifted by the shadow offset, the wall bleeds into the widget
    // producing the inset shadow.
    final wallSize  = rect.longestSide * 3;
    final outerPath = Path()
      ..addRect(Rect.fromCenter(
          center: rect.center, width: wallSize, height: wallSize));
    final innerPath = Path()..addRRect(rrect);
    final wallPath  = Path.combine(PathOperation.difference, outerPath, innerPath);

    // Use blurRadius directly (not blurSigma) so the result matches CSS:
    //   CSS blur:4px → sigma = 4
    //   Flutter blurSigma for radius=4 → ~2.81  (too soft)
    final paint = Paint()
      ..color      = shadow.color
      ..maskFilter = MaskFilter.blur(BlurStyle.normal, shadow.blurRadius);

    // Save a layer bounded to the widget rect, clip to its shape, then draw
    // the translated wall — only the portion that falls inside the clip
    // (the inset area) is visible.
    canvas.saveLayer(rect, Paint());
    canvas.clipRRect(rrect);
    canvas.save();
    canvas.translate(shadow.offset.dx, shadow.offset.dy);
    canvas.drawPath(wallPath, paint);
    canvas.restore(); // undo translate
    canvas.restore(); // restore clip layer
  }
}
